import React, {useEffect} from 'react'
import { useDispatch } from 'react-redux'
import './GoodsBlock.scss'
import Goods from '../Goods/Goods'
import InitialJson from "../../data/data.json"
import { loadGoods } from '../../actions/goods'


function GoodsBlock() {
    const dispatch = useDispatch()

    useEffect(() => {
        dispatch(loadGoods(InitialJson))
    }, [dispatch])

    const generateGoods = () => {
        return InitialJson.map(item => {
            return <Goods {...item} key={item.id} />
        })
    }

    return (
        <div className="goods-block">
            {generateGoods()}
        </div>
    )
}

export default GoodsBlock