import { SEND_BILL, SEND_STATUS, CLEAR_SCREEN_ALL } from '../constants/constants.js'


export function sendBill(data) {
    return {
        type: SEND_BILL,
        payload: data,
    }
}

export function sendStatus(data) {
    return {
        type: SEND_STATUS,
        payload: data,
    }
}

export function clearScreen() {
    return {
        type: CLEAR_SCREEN_ALL
    }
}