import {
    SET_CHANGE,
    SET_CHANGE_ITEM,
    CLEAR_CHANGE_ALL
} from '../constants/constants.js'


const initialState = {
    change: null,
    item: null
}


export default function change(state = initialState, action) {
    switch (action.type) {
        case SET_CHANGE:
            return { ...state, change: action.payload }
        case SET_CHANGE_ITEM:
            return { ...state, item: action.payload }
        case CLEAR_CHANGE_ALL:
            return { change: null, item: null }
        default:
            return state
    }
}