import { SEND_BILL, SEND_STATUS, CLEAR_SCREEN_ALL } from '../constants/constants.js'


const initialState = {
    depositedBanknotes: null,
    status: null
}


export default function app(state = initialState, action) {
    switch (action.type) {
        case SEND_BILL:
            return {
                ...state,
                depositedBanknotes: Number(state.depositedBanknotes) + Number(action.payload)
            }
        case SEND_STATUS:
            return {
                ...state, status: action.payload
            }
        case CLEAR_SCREEN_ALL:
            return {
                depositedBanknotes: null, status: null
            }
        default:
            return state
    }
}