import React, { useState, useEffect } from 'react'
import { useSelector, useDispatch } from 'react-redux'
import './ShortСhange.scss'
import { clearChangeAll } from '../../actions/change'
import { clearScreen } from '../../actions/screen'


function ShortСhange() {
    const dispatch = useDispatch()
    const change = useSelector(store => store.change.change)
    const changeItem = useSelector(store => store.change.item)
    const [animClass, setAnimClass] = useState('')



    useEffect(() => {
        if (changeItem !== null) {
            setAnimClass('animate')
        } else {
            setAnimClass('')
        }
    }, [changeItem])


    const generateChange = () => {
        if (change === null) {
            return
        }

        return change.map(({ coin, count }) => {
            return (
                <div key={coin}>
                    <span>{coin} руб. :</span>  <span>{count} coins </span>
                </div>
            )
        })
    }

    const generateChangeItem = () => {
        if (changeItem === null) {
            return
        }


        let { name, price, currency } = changeItem
        return (
            <>
                <div>{name}</div>
                <div>{price} {currency}</div>
            </>
        )
    }

    const handleClick = () => {
        dispatch(clearChangeAll())
        dispatch(clearScreen())
    }


    return (
        <div className="short-change">
            <p className="short-change__desc"> The machine gives change in 1, 2, 5 and 10 &#8381; coins</p>
            <div className="short-change__wrap">
                <div className="short-change-screen">
                    {generateChange()}
                </div>
                <div
                    className={`short-change-product ${animClass}`}
                    onClick={handleClick}
                >
                    {generateChangeItem()}
                </div>
                <div className="short-change-coin">
                    <div className="short-change-coin__we"></div>
                </div>
            </div>
        </div>
    )
}

export default ShortСhange