import React from 'react'
import './Goods.scss'


function Goods({ id, name, size, measure, price, currency, imgSrc }) {
    return (
        <div className="goods">
            <div className="goods__wrap-img">
                <img className="goods__img" src={imgSrc} alt={name} />
            </div>
            <div className="goods__bottom">
                <span className="goods__name">{name} </span>
                <span className="goods__price">{price} {currency}</span>
                <span className="goods__size">{size} {measure}</span>
                
                <span className="goods__id">{id}</span>
            </div>
        </div>
    )
}

export default Goods