import React, { useState, useEffect } from 'react'
import { useSelector, useDispatch } from 'react-redux'
import './NumbersPanel.scss'
import { setChange, setChangeItem } from '../../actions/change'
import { sendStatus } from '../../actions/screen'


function NumbersPanel() {
    const dispatch = useDispatch()
    const depositedBanknotes = useSelector(store => store.screen.depositedBanknotes)
    const goods = useSelector(store => store.goods)
    const [count, setCount] = useState('')
    const [disabled, setDisabled] = useState(true)
    const [placeHolder, changePlaceHolder] = useState('. . .')
    const coins = [1, 2, 5, 10]


    useEffect(() => {
        if (!depositedBanknotes) {
            setDisabled(true)
        } else {
            setDisabled(false)
            changePlaceHolder('Choose product . . .')
        }
    }, [depositedBanknotes])


    const handleSubmit = e => {
        e.preventDefault()

        if (checkInStock(count)) {
            let { price, name, currency } = goods.find(item => item.id === Number(count))

            let balance = checkBalance(price)

            if (balance < 0) {
                return false
            }

            let massCoins = calculateChange(balance)
            let res = []

            for (let i = 0; i < massCoins.length; i++) {
                if (massCoins[i] !== 0) {
                    res.push({
                        count: massCoins[i],
                        coin: coins[i]
                    })
                }
            }

            setDisabled(true)
            setCount('')

            dispatch(setChange(res))
            dispatch(setChangeItem({ name, price, currency }))
            dispatch(sendStatus('Take your product and change!'))
        } else {
            dispatch(sendStatus('There is no product with this number!'))
        }

        function checkInStock(count) {
            return goods.some(item => item.id === Number(count))
        }

        function checkBalance(price) {
            let balance = depositedBanknotes - price
            if (balance < 0) {
                dispatch(sendStatus('Not enough money!'))
            }
            return balance
        }

        function calculateChange(change) {
            let toGiveBack = Array(coins.length).fill(0)

            for (let i = coins.length; i >= 0; i--) {
                while (coins[i] <= change) {
                    change = change - coins[i]
                    toGiveBack[i] += 1
                }
            }
            return toGiveBack
        }
    }

    const handleChange = e => {
        e.persist()
        setCount(e.target.value)
    }


    return (
        <div className="numpanel">
            <form onSubmit={handleSubmit}>
                <input
                    type="number"
                    className="numpanel__input"
                    placeholder={`${placeHolder}`}
                    value={count}
                    onChange={handleChange}
                    disabled={disabled}
                />
            </form>
        </div>
    )
}

export default NumbersPanel