import React, { useState } from 'react'
import { useDispatch } from 'react-redux'
import './BillAcceptor.scss'
import { ReactComponent as Logo } from '../../assets/svg/triangle.svg'
import { sendBill } from '../../actions/screen'
import { sendStatus } from '../../actions/screen'


function BillAcceptor() {
    const dispatch = useDispatch()
    const permittedBanknotes = [50, 100, 200, 500, 1000]
    const [bill, setBill] = useState('')


    const handleChange = e => {
        setBill(e.target.value)
    }


    const handleSubmit = e => {
        e.preventDefault()

        if (bill === '') {
            return
        }

        if (permittedBanknotes.includes(Number(bill))) {
            dispatch(sendStatus('Choose product . . .'))
            dispatch(sendBill(bill))
            setBill('')
        } else {
            dispatch(sendStatus('Unknown banknote!'))
        }
    }


    return (
        <div className="bill-acceptor">
            <p className="bill-acceptor__text">Insert <br /> banknotes </p>
            <Logo className="bill-acceptor__triangle" />

            <form onSubmit={handleSubmit}>
                <input
                    className="bill-acceptor__num"
                    type="number"
                    name=""
                    placeholder="Insert banknotes"
                    value={bill}
                    onChange={handleChange}
                />
            </form>

            <p className="bill-acceptor__desc">Available banknotes: 50, 100, 200, 500 or 1000 &#8381;.</p>
        </div>
    )
}

export default BillAcceptor