import React from 'react'
import { useSelector } from 'react-redux'
import './Screen.scss'


function Screen() {
    const depositedBanknotes = useSelector(store => store.screen.depositedBanknotes)
    const status = useSelector(store => store.screen.status)

    return (
        <div className="screen">
            {!depositedBanknotes && !status && <span>. . .</span>}

            {depositedBanknotes &&
                <>
                    <span>Inserted money: {`${depositedBanknotes}`} руб.</span>
                    <br />
                </>
            }

            {status && <span>{status}</span>}
        </div>
    )
}

export default Screen