import {
    SET_CHANGE,
    SET_CHANGE_ITEM,
    CLEAR_CHANGE_ALL
} from '../constants/constants.js'


export function setChange(data) {
    return {
        type: SET_CHANGE,
        payload: data,
    }
}

export function clearChangeAll() {
    return {
        type: CLEAR_CHANGE_ALL,
    }
}

export function setChangeItem(item) {
    return {
        type: SET_CHANGE_ITEM,
        payload: item,
    }
}
